+    let rc = unsafe { semop(-1, std::ptr::null_mut(), 1) };
+    assert_eq!(rc, -1);
+    assert!(
+        is_expected_sysvipc_errno(errno_value()),
+        "unexpected errno for semop null payload: {}",
+        errno_value()
+    );
+}
